create table dirkspzm32.s_host_cfg (
    sid                   varchar2(2 char) not null enable,
    firma_nr              number(6, 0) not null enable,
    cfg_name              varchar2(50 char) not null enable,
    sap_destination       varchar2(30 char) not null enable,
    sap_username          varchar2(30 char),
    sap_password          varchar2(30 char) not null enable,
    sap_modus             varchar2(30 char),
    sap_hostname          varchar2(30 char),
    sap_sysnr             number(*, 5),
    sap_gwhost            varchar2(30 char),
    sap_gwserver          varchar2(30 char),
    sap_client            varchar2(30 char),
    sap_sprache           varchar2(30 char),
    sap_trace             varchar2(30 char),
    sap_balancing         number(*, 5),
    sap_applicationserver varchar2(30 char),
    sap_gateway           varchar2(30 char),
    sap_server            varchar2(30 char),
    host_typ              varchar2(10 char) not null enable
);

alter table dirkspzm32.s_host_cfg
    add constraint pk_s_host_cfg
        primary key ( sid,
                      firma_nr,
                      cfg_name )
            using index enable;


